#include <iostream>

using namespace std;

void tryToChange(int n)
{
    n = 999;
}

int main()
{
    int x = 5;

    tryToChange(x);

    cout << x << endl;

    return 0;
}

void doubleIt(int n)
{
    n = n * 2; // only changes the local copy
}

int main()
{
    int x = 5;
    doubleIt(x);
    cout << x; // still 5, not 10!
}

void tryToChange(double d) { d = 0.0; }
void tryToChange(char c) { c = 'Z'; }
void tryToChange(bool b) { b = false; }

